  5→  "description": "A request message sent from the core engine to a language frontend.",
  6→  "type": "object",
  7→  "required": ["protocol_version", "id", "command"],
  8→  "properties": {
  9→    "protocol_version": {
 10→      "type": "string",
 11→      "description": "Protocol version for compatibility checking.",
 12→      "pattern": "^\\d+\\.\\d+\\.\\d+$"
 13→    },
 14→    "id": {
 15→      "type": "integer",
 16→      "minimum": 0,
 17→      "description": "Unique identifier for correlating responses to requests."
 18→    },
 19→    "command": {
 20→      "type": "string",
 21→      "enum": ["handshake", "analyze", "instrument", "execute", "setup", "teardown", "generate", "shutdown"],
 22→      "description": "The command to execute."
 23→    }
 24→  },
 25→  "oneOf": [
 26→    { "$ref": "#/$defs/handshake_request" },
 27→    { "$ref": "#/$defs/analyze_request" },
 28→    { "$ref": "#/$defs/instrument_request" },
 29→    { "$ref": "#/$defs/execute_request" },
 30→    { "$ref": "#/$defs/generate_request" },
 31→    { "$ref": "#/$defs/shutdown_request" }
 32→  ],
