 34→    "handshake_request": {
 35→      "type": "object",
 36→      "properties": {
 37→        "command": { "const": "handshake" },
 38→        "capabilities": {
 39→          "type": "array",
 40→          "items": { "type": "string" },
 41→          "description": "Capabilities supported by the core."
 42→        }
 43→      },
 44→      "required": ["command", "capabilities"]
 45→    },
 46→    "analyze_request": {
 47→      "type": "object",
 48→      "properties": {
 49→        "command": { "const": "analyze" },
 50→        "file": {
 51→          "type": "string",
 52→          "description": "Path to the source file."
 53→        },
 54→        "function": {
