 56→          "description": "Name of the function to analyze. If null/absent, analyze all exported functions."
 57→        },
 58→        "project_root": {
 59→          "type": ["string", "null"],
 60→          "description": "Path to the detected project root directory."
 61→        }
 62→      },
 63→      "required": ["command", "file"]
 64→    },
 65→    "instrument_request": {
 66→      "type": "object",
 67→      "properties": {
 68→        "command": { "const": "instrument" },
 69→        "file": {
 70→          "type": "string",
 71→          "description": "Path to the source file."
 72→        },
 73→        "function": {
 74→          "type": "string",
 75→          "description": "Name of the function to instrument."
 76→        },
 77→        "mocks": {
 78→          "type": "array",
 79→          "items": { "$ref": "mock-config.schema.json" },
