 82→        "project_root": {
 83→          "type": ["string", "null"],
 84→          "description": "Path to the detected project root directory."
 85→        }
 86→      },
 87→      "required": ["command", "file", "function", "mocks"]
 88→    },
 89→    "execute_request": {
 90→      "type": "object",
 91→      "properties": {
 92→        "command": { "const": "execute" },
 93→        "function": {
 94→          "type": "string",
 95→          "description": "Fully qualified function identifier."
 96→        },
 97→        "inputs": {
 98→          "type": "array",
 99→          "description": "Input values for the function parameters (JSON-encoded)."
100→        },
101→        "mocks": {
102→          "type": "array",
103→          "items": { "$ref": "mock-config.schema.json" },
104→          "description": "Mock configurations for external dependencies."
105→        }
106→      },
107→      "required": ["command", "function", "inputs", "mocks"]
108→    },
109→    "generate_request": {
110→      "type": "object",
111→      "properties": {
112→        "command": { "const": "generate" },
113→        "file": {
114→          "type": "string",
115→          "description": "Path to the generator file."
116→        },
117→        "name": {
118→          "type": "string",
119→          "description": "Name of the type or parameter to generate a value for."
120→        },
121→        "kind": {
122→          "type": "string",
123→          "enum": ["type_name", "param_name"],
124→          "description": "Whether this generator targets a type name or a parameter name."
125→        },
126→        "recipe": {
127→          "description": "Reconstruction recipe from a previous generation. When present, the generator should reproduce the value from this recipe."
128→        },
129→        "project_root": {
130→          "type": ["string", "null"],
131→          "description": "Path to the detected project root directory."
132→        }
133→      },
134→      "required": ["command", "file", "name", "kind"]
135→    },
136→    "shutdown_request": {
137→      "type": "object",
138→      "properties": {
139→        "command": { "const": "shutdown" }
140→      },
141→      "required": ["command"]
142→    }
143→  }
144→}
